  ('heelevel3-5ff21eeb-moex-00034', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關納稅義務人申請延期或分期繳納之規定，何者錯誤？', '["延期或分期繳納之期間不得逾3年", "納稅義務人因天災、事變、不可抗力之事由得申請延期或分期繳納", "依法應繳納稅捐，因客觀事實發生財務困難得申請分期繳納", "納稅義務人為經濟弱勢者得申請延期或分期繳納"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00035', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '乙公司對於北區國稅局新竹分局核定之營利事業所得稅額300萬元不服，經申請復查及訴願均未 獲得變更，請問乙公司應向下列那一機關提起行政訴訟？', '["財政部", "新竹地方法院行政訴訟庭", "臺北高等行政法院地方行政訴訟庭", "臺北高等行政法院高等行政訴訟庭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00036', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列何者非屬租稅法源？', '["租稅法律", "租稅協定", "司法判決", "解釋函令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00037', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '乙公司為加值型營業人，於今年 2 月銷售時未開立統一發票，經查明認定之銷售額總額為 60 萬 元，依稅捐稽徵法第44條規定，處3萬元罰鍰；依加值型及非加值型營業稅法第51條漏報銷售 額之規定，處12萬元罰鍰。請問乙公司應繳多少罰鍰？', '["15萬元", "12萬元", "9萬元", "3萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00038', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '下列有關租稅之處罰何者錯誤？', '["營利事業取得非實際交易對象所開立之憑證，如經查明確有進貨事實及該項憑證確由實際銷貨 之營利事業所交付，且實際銷貨之營利事業已依法處罰者，免予處罰", "納稅義務人以詐術或其他不正當方法逃漏稅捐，自動向稅捐稽徵機關補報並補繳所漏稅款者， 凡屬未經檢舉、未經稅捐稽徵機關或財政部指定之調查人員進行調查之案件者，免予處罰", "稅法規定應處罰鍰之行為，其情節輕微，或漏稅在一定金額以下者，得減輕或免予處罰", "納稅義務人違反稅捐稽徵法或稅法之規定，適用行為時之法律。但行為前之法律有利於納稅義 務人者，適用最有利於納稅義務人之法律"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
  ('heelevel3-5ff21eeb-moex-00039', 'heelevel3-5ff21eeb', 'heelevel3-5ff21eeb-moex-114-9bdab6d6', 'sub-heelevel3-5ff21eeb-03', NULL, 'single_choice', '甲有A、B二屋，A屋遭法拍，拍定價為350萬元，其積欠的債務及稅捐如下：①信用卡刷卡欠', '["B屋之銀行抵押借款200萬元", "法拍A屋的土地增值稅25萬元", "B屋房屋稅 2萬元，地價稅1萬元。依稅捐稽徵法之規定，上開拍定價款應清償上開債務及稅捐之順序為何？", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:06+00:00", "source_pdf_sha1": "165a9899d3c6", "answer_pdf_sha1": "d2b8f737eb90", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "224", "s": "0703", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "財稅法務"}'::jsonb, NULL),
